import React, { useState } from "react";
import { motion, useAnimation } from "framer-motion";

const TestimonialCard = ({ card }) => {
  const [flipped, setFlipped] = useState(false);
  const controls = useAnimation();

  const handleClick = () => {
    setFlipped(!flipped);
    controls.start({
      rotateY: flipped ? 0 : 180,
      transition: { duration: 0.6 },
    });
  };

  return (
    <motion.div
      style={{
        width: "320px",
        minHeight: "300px",
        perspective: 1000,
        cursor: "pointer",
        margin: "0 auto",
      }}
      onClick={handleClick}
      animate={controls}
      initial={{ rotateY: 0 }}
    >
      {/* Frente */}
      <motion.div
        style={{
          position: "relative",
          width: "100%",
          height: "100%",
          borderRadius: "10px",
          backgroundColor: "#154734",
          color: "#e4d0a9",
          boxShadow: "0 2px 8px rgba(0,0,0,0.3)",
          padding: "2rem",
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
          justifyContent: "center",
          textAlign: "center",
          backfaceVisibility: "hidden",
          WebkitBackfaceVisibility: "hidden",
          rotateY: 0,
          position: "absolute",
          top: 0,
          left: 0,
        }}
      >
        <div
          style={{ marginBottom: "1.5rem", fontWeight: "bold", fontSize: "1.5rem" }}
        >
          {card.title}
        </div>
        <p style={{ marginBottom: "1rem", fontSize: "1rem", lineHeight: "1.5" }}>
          {card.text}
        </p>
        <div style={{ fontSize: "0.9rem", fontWeight: "400", opacity: 0.8 }}>
          {card.role}
        </div>
      </motion.div>

      {/* Atrás */}
      <motion.div
        style={{
          position: "absolute",
          width: "100%",
          height: "100%",
          borderRadius: "10px",
          backgroundColor: "#e4d0a9",
          color: "#154734",
          boxShadow: "0 2px 8px rgba(0,0,0,0.3)",
          padding: "2rem",
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
          justifyContent: "center",
          textAlign: "center",
          backfaceVisibility: "hidden",
          WebkitBackfaceVisibility: "hidden",
          rotateY: 180,
          top: 0,
          left: 0,
          pointerEvents: "none",
          overflowY: "auto",
        }}
      >
        {card.backType === "list" && (
          <>
            <h3 style={{ fontWeight: "bold", fontSize: "1.5rem", marginBottom: "1rem" }}>
              Integrantes
            </h3>
            <ul style={{ textAlign: "left", paddingLeft: "1rem", maxHeight: "200px" }}>
              {card.backContent.map((name, i) => (
                <li key={i} style={{ marginBottom: "0.4rem" }}>{name}</li>
              ))}
            </ul>
          </>
        )}
        {card.backType === "image" && (
          <img
            src={card.backContent}
            alt="Imagen trasera"
            style={{ maxWidth: "150px", borderRadius: "50%" }}
          />
        )}
      </motion.div>
    </motion.div>
  );
};

export default TestimonialCard;
